// Extract training data from webhook
const body = $input.first().json.body || $input.first().json;

const companySlug = body.company_slug || 'default';
const assistantName = body.assistant_name || 'MIA';
const companyName = body.company_name || 'la empresa';
const userMessage = body.user_message || '';
const conversationHistory = body.conversation_history || [];
const openaiApiKey = body.openai_api_key || '';
const qdrantHost = body.qdrant_host || 'https://qdrant-production-f4e7.up.railway.app';
const timestamp = new Date().toISOString();

// Create collection name
const collectionName = 'company_' + companySlug.replace(/[^a-z0-9_-]/gi, '_').toLowerCase() + '_knowledge';

// Build system prompt for the training agent
const systemPrompt = `Eres ${assistantName}, el asistente de entrenamiento de ${companyName}.

Tu rol es:
1. Ayudar al usuario a entrenar y mejorar el bot de la empresa
2. Entender ejemplos de conversaciones que te den
3. Aprender correcciones sobre cómo deberías responder
4. Registrar información importante sobre la empresa y sus clientes

Cuando el usuario te de un ejemplo o corrección:
- Confirma que lo has entendido
- Muestra cómo responderías en esa situación
- Pregunta si hay más ejemplos o información

Sé amigable, profesional y muestra que estás aprendiendo.`;

return {
  json: {
    company_slug: companySlug,
    assistant_name: assistantName,
    company_name: companyName,
    user_message: userMessage,
    conversation_history: conversationHistory,
    collection_name: collectionName,
    openai_api_key: openaiApiKey,
    qdrant_host: qdrantHost,
    timestamp: timestamp,
    system_prompt: systemPrompt
  }
};

// Prepare Qdrant search request
const prevData = $('Prepare Training Data').first().json;
const embedding = $input.first().json.data[0].embedding;

return {
  json: {
    ...prevData,
    query_vector: embedding
  }
};

// Build context from Qdrant results and prepare OpenAI request
const prevData = $('Prepare Search').first().json;
const searchResults = $input.first().json.result || [];

// Extract relevant context from search results
let contextText = '';
if (searchResults && searchResults.length > 0) {
  contextText = searchResults
    .filter(r => r.score > 0.5)
    .map(r => r.payload?.text || '')
    .filter(t => t)
    .join('\n\n---\n\n');
}

if (!contextText) {
  contextText = 'Sin contexto previo en la base de conocimiento.';
}

// Build messages array for chat completion
const messages = [
  {
    role: 'system',
    content: prevData.system_prompt + '\n\nCONTEXTO DE LA EMPRESA (información ya aprendida):\n' + contextText
  }
];

// Add conversation history if available
if (prevData.conversation_history && prevData.conversation_history.length > 0) {
  for (const msg of prevData.conversation_history.slice(-10)) {
    messages.push({
      role: msg.role || 'user',
      content: msg.content || msg.message || ''
    });
  }
}

// Add current user message
messages.push({
  role: 'user',
  content: prevData.user_message
});

return {
  json: {
    ...prevData,
    context_text: contextText,
    messages: messages
  }
};

// Process AI response and decide if we should save
const prevData = $('Build Context & Messages').first().json;
const aiResponse = $input.first().json.choices[0].message.content || '';

// Keywords that indicate this should be saved as knowledge
const saveKeywords = [
  'ejemplo', 'así deberías', 'responde así', 'cuando pregunten',
  'siempre', 'nunca', 'importante', 'recuerda', 'nuestro',
  'nuestros', 'vendemos', 'ofrecemos', 'horario', 'precio',
  'correcto', 'incorrecto', 'mejor', 'información', 'producto',
  'servicio', 'cliente', 'empresa', 'política', 'procedimiento'
];

const lowerMessage = prevData.user_message.toLowerCase();
const shouldSave = saveKeywords.some(kw => lowerMessage.includes(kw)) || prevData.user_message.length > 100;

// Prepare text to save (if applicable)
let textToSave = '';
if (shouldSave) {
  textToSave = `EJEMPLO DE ENTRENAMIENTO\n\nUsuario: ${prevData.user_message}\n\nRespuesta del asistente: ${aiResponse}\n\nFecha: ${prevData.timestamp}`;
}

return {
  json: {
    response: aiResponse,
    should_save: shouldSave,
    text_to_save: textToSave,
    company_slug: prevData.company_slug,
    collection_name: prevData.collection_name,
    openai_api_key: prevData.openai_api_key,
    qdrant_host: prevData.qdrant_host
  }
};

// Prepare point for Qdrant - Get data from Should Save? node which preserves Process Response data
const shouldSaveData = $('Should Save?').first().json;
const embedding = $input.first().json.data[0].embedding;

// Get text_to_save - it should be passed through from Process Response
const textToSave = shouldSaveData.text_to_save || '';

// Generate UUID v4
const uuid = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
  const r = Math.random() * 16 | 0;
  const v = c === 'x' ? r : (r & 0x3 | 0x8);
  return v.toString(16);
});

return {
  json: {
    id: uuid,
    vector: embedding,
    payload: {
      text: textToSave,
      filename: 'training_examples.txt',
      category: 'entrenamiento',
      company_slug: shouldSaveData.company_slug,
      chunk_index: 0,
      total_chunks: 1
    },
    collection_name: shouldSaveData.collection_name,
    qdrant_host: shouldSaveData.qdrant_host,
    response: shouldSaveData.response
  }
};

// Return response (saved path)
const prevData = $('Prepare Qdrant Point').first().json;
return {
  json: {
    response: prevData.response,
    saved: true,
    message: 'Guardado en la base de conocimiento'
  }
};

// Return response (not saved path)
const prevData = $('Process Response').first().json;
return {
  json: {
    response: prevData.response,
    saved: false
  }
};

